using System.Collections.Concurrent;
using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────────────────

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// ── Chat client (MEAI abstraction over OpenAI) ────────────────────────────────

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ── Tools ──────────────────────────────────────────────────────────────────────

var notebook = new Notebook();

List<AITool> tools =
[
    AIFunctionFactory.Create(WebSearchTool.Search),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetAllNotes),
];

// ── Agent ──────────────────────────────────────────────────────────────────────

const string instructions = """
    You are a research agent. When given a topic you MUST:
      1. Use the SearchWeb tool multiple times with different queries to gather
         broad and detailed information about the topic.
      2. After each search, use SaveNote to record the key findings.
      3. When you have gathered enough information, use GetAllNotes to review
         everything you have collected.
      4. Finally, write a comprehensive summary that synthesizes all your notes.
         The summary should be well-structured with sections and cite the sources
         found during search.
    Always search at least twice with different queries before summarizing.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches a topic using web search and note-taking tools",
    tools: tools);

// ── Run ────────────────────────────────────────────────────────────────────────

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔬 AI Research Agent           ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n📋 Researching: {topic}\n");

var session = new ChatClientAgentSession();

var options = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

await foreach (var update in agent.RunStreamingAsync(topic, session, options))
{
    // Only print final text content (tool calls are logged by the tools themselves)
    if (update.Content is { Length: > 0 })
    {
        Console.Write(update.Content);
    }
}

Console.WriteLine("\n\n✅ Research complete.");

// ── Helpers ────────────────────────────────────────────────────────────────────

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input) ? "quantum computing" : input;
}

// ═══════════════════════════════════════════════════════════════════════════════
//  Tool implementations
// ═══════════════════════════════════════════════════════════════════════════════

/// <summary>Simulated web search tool. Replace the body with a real search API
/// (Bing Search, Google Custom Search, etc.) for production use.</summary>
static class WebSearchTool
{
    [Description("Search the web for information on a query. Returns relevant snippets and sources.")]
    public static string Search(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        // Simulated results — swap with a real HTTP call to a search API.
        return query.ToLowerInvariant() switch
        {
            var q when q.Contains("quantum") && q.Contains("application") => """
                [1] "Quantum computing applications span cryptography (Shor's algorithm breaks RSA), drug discovery (molecular simulation), financial modeling (portfolio optimization), and logistics (route optimization). Pharma companies like Roche are piloting quantum chemistry simulations." — Nature Reviews Physics
                [2] "Google's Willow chip demonstrated quantum error correction below threshold in 2025, a prerequisite for practical applications. IBM's Heron processor targets 10,000-gate circuits for chemistry." — MIT Technology Review
                """,
            var q when q.Contains("quantum") && (q.Contains("challenge") || q.Contains("limitation") || q.Contains("obstacle")) => """
                [1] "Major challenges: qubit decoherence limits computation time, error rates remain high (~0.1%), and cryogenic cooling requirements make systems expensive. Current quantum computers have 1,000-1,200 qubits but need millions for practical cryptography." — IEEE Spectrum
                [2] "The 'quantum winter' debate: skeptics argue useful quantum advantage is decades away for most problems. Hybrid classical-quantum approaches are the near-term pragmatic path." — Scientific American
                """,
            var q when q.Contains("quantum") => """
                [1] "Quantum computing leverages qubits in superposition and entanglement to perform massively parallel computations. Unlike classical bits (0 or 1), qubits represent both states simultaneously." — Nature Reviews Physics
                [2] "IBM, Google, Microsoft, and IonQ lead the hardware race. IBM's 1,121-qubit Condor and Google's Willow chip represent 2024-2025 milestones. Trapped-ion and superconducting approaches compete." — MIT Technology Review
                [3] "Quantum volume and circuit layer operations per second (CLOPS) are emerging benchmarks beyond raw qubit count." — arxiv.org/abs/2401.xxxxx
                """,
            var q when q.Contains("artificial intelligence") || q.Contains("ai") => """
                [1] "AI in 2026 is dominated by foundation models exceeding 1 trillion parameters, multimodal reasoning, and agentic workflows that chain tool use with planning." — IEEE Spectrum
                [2] "Key concerns: alignment research, energy consumption (training a frontier model ≈ 10 GWh), job displacement in knowledge work, and deepfake proliferation." — The Economist
                [3] "Breakthroughs in code generation, mathematical reasoning, and scientific discovery. AI agents now autonomously conduct multi-step research and software engineering tasks." — Science Magazine
                """,
            var q when q.Contains("climate") || q.Contains("renewable") => """
                [1] "Global renewable energy capacity surpassed 4,000 GW in 2025. Solar PV alone added 600 GW, driven by cost reductions to $0.02/kWh in optimal locations." — IRENA Global Report
                [2] "Battery storage deployments tripled, with grid-scale lithium-iron-phosphate systems dominating. Sodium-ion batteries emerging as a low-cost alternative." — BloombergNEF
                [3] "Despite progress, fossil fuels still supply 75% of primary energy. The 1.5°C target requires tripling renewable deployment rates by 2030." — IEA World Energy Outlook
                """,
            _ => $"""
                [1] "Overview of {query}: A rapidly evolving field with significant recent developments in both research and industry applications." — Wikipedia
                [2] "Recent advances in {query} have led to new practical applications across healthcare, finance, and engineering domains." — ResearchGate
                [3] "Experts predict major breakthroughs in {query} within 3-5 years, driven by increased funding and interdisciplinary collaboration." — ScienceDaily
                """,
        };
    }
}

/// <summary>Note-taking tool that persists findings during a research session.</summary>
sealed class Notebook
{
    private readonly ConcurrentDictionary<string, string> _notes = new();

    [Description("Save a research note with a title and content. Use this to record important findings.")]
    public string SaveNote(
        [Description("Short descriptive title")] string title,
        [Description("Content of the note")] string content)
    {
        _notes[title] = content;
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note '{title}' saved successfully.";
    }

    [Description("Retrieve all saved research notes to review before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.IsEmpty)
            return "No notes saved yet.";

        Console.WriteLine($"  📖 Retrieving {_notes.Count} note(s)");

        var sb = new System.Text.StringBuilder();
        foreach (var (title, content) in _notes)
        {
            sb.AppendLine($"## {title}");
            sb.AppendLine(content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

